oxy_webhelp_navlinks = {"arch_loc_migration-d30753e6705":{"topics":[{"title":"Archival location migration planning","shortdesc":"<p class=\"shortdesc\">Planning the migration scope, SLA Domain configurations, tool selection, and         sequencing before migrating archival data minimizes disruption and ensures a smooth         transition. Effective planning reduces the risk of errors, lowers storage costs from running         parallel systems, and ensures that the migration preserves data integrity and retention         requirements.<\/p>","href":"archival\/arch_loc_migration_planning.html","attributes":{"data-id":"arch_loc_migration_planning"},"menu":{"hasChildren":false},"tocID":"arch_loc_migration_planning-d30753e6716","topics":[]},{"title":"Prerequisites for archival location migration","shortdesc":"<p class=\"shortdesc\">Before migrating an archival location, ensure that your source location, Rubrik         cluster, and SLA Domain configurations meet all the requirements for the selected migration         type.<\/p>","href":"archival\/arch_loc_migration_prereq.html","attributes":{"data-id":"arch_loc_migration_prereq"},"menu":{"hasChildren":false},"tocID":"arch_loc_migration_prereq-d30753e6727","topics":[]},{"title":"Rubrik data mover and AWS DataSync agent requirements","shortdesc":"<p class=\"shortdesc\">Information about the compute, network, and firewall requirements for deploying the         Rubrik data mover and the AWS DataSync agent in your environment. <\/p>","href":"archival\/arch_loc_agent_reqs.html","attributes":{"data-id":"arch_loc_agent_reqs"},"menu":{"hasChildren":false},"tocID":"arch_loc_agent_reqs-d30753e6738","topics":[]},{"title":"Archival location migration workflow","shortdesc":"<p class=\"shortdesc\">The archival location migration workflow describes the responsibilities of the         customer and Rubrik Professional Services in each phase of the migration.<\/p>","href":"archival\/arch_loc_migration_workflow.html","attributes":{"data-id":"arch_loc_migration_workflow"},"menu":{"hasChildren":false},"tocID":"arch_loc_migration_workflow-d30753e6749","topics":[]},{"title":"Customer-hosted migration process","shortdesc":"<p class=\"shortdesc\">You can migrate an archival location to RCV by running the migration tool in your own         AWS environment.<\/p>","href":"archival\/arch_loc_cust_managed_migration_process.html","attributes":{"data-id":"arch_loc_cust_managed_migration_process"},"menu":{"hasChildren":false},"tocID":"arch_loc_cust_managed_migration_process-d30753e6760","next":"arch_loc_cust_managed_migration_process-d30753e6760"},{"title":"Rubrik-hosted migration process","shortdesc":"<p class=\"shortdesc\">You can migrate an archival location to RCV by authorizing Rubrik to run the         migration tool within the Rubrik AWS environment.<\/p>","href":"archival\/arch_loc_rbk_managed_migration_process.html","attributes":{"data-id":"arch_loc_rbk_managed_migration_process"},"menu":{"hasChildren":false},"tocID":"arch_loc_rbk_managed_migration_process-d30753e6818","next":"arch_loc_rbk_managed_migration_process-d30753e6818"},{"title":"Updating SLA Domains after migrating to RCV Archive tier","shortdesc":"<p class=\"shortdesc\">After migrating an S3-compatible archival location to an RCV Archive tier location,         you must update the associated SLA Domains to enable instant tiering to Glacier Deep Archive         before re-enabling the location.<\/p>","href":"archival\/arch_loc_update_sla_archive_tier_migration.html","attributes":{"data-id":"arch_loc_update_sla_archive_tier_migration"},"menu":{"hasChildren":false},"tocID":"arch_loc_update_sla_archive_tier_migration-d30753e6873","topics":[]}]}};